import{_ as a,o as d,c as e,a2 as r}from"./chunks/framework.Bkqnpl2X.js";const c=JSON.parse('{"title":"第四编 系统工程与管理","description":"","frontmatter":{},"headers":[],"relativePath":"guide/part4-index.md","filePath":"guide/part4-index.md","lastUpdated":1780443280000}'),i={name:"guide/part4-index.md"};function h(p,t,s,o,l,n){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="第四编-系统工程与管理" tabindex="-1">第四编 系统工程与管理 <a class="header-anchor" href="#第四编-系统工程与管理" aria-label="Permalink to &quot;第四编 系统工程与管理&quot;">​</a></h1><blockquote><p>第37-52章 | 系统思维驱动的阀门研发管理</p></blockquote><hr><h2 id="本编概述" tabindex="-1">本编概述 <a class="header-anchor" href="#本编概述" aria-label="Permalink to &quot;本编概述&quot;">​</a></h2><p>第四编从系统工程与项目管理的视角，探讨如何高效、高质量地组织航空航天阀门的研发活动。内容覆盖系统工程管理、项目管理、质量保证、产品数据管理、数字孪生、全球产业格局分析、故障分析方法、仿真工具生态、材料与标准数据库，以及完整的参考文献体系。本编共16章，是技术管理者和系统工程师的必备参考。</p><hr><h2 id="章节导航" tabindex="-1">章节导航 <a class="header-anchor" href="#章节导航" aria-label="Permalink to &quot;章节导航&quot;">​</a></h2><table tabindex="0"><thead><tr><th>章节</th><th>标题</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="/avis-web/guide/part4/chapter-37">第37章</a></td><td>系统工程管理</td><td>INCOSE SE流程、技术规划、决策分析、风险管理</td></tr><tr><td><a href="/avis-web/guide/part4/chapter-38">第38章</a></td><td>项目管理</td><td>WBS、进度管理、资源分配、挣值管理</td></tr><tr><td><a href="/avis-web/guide/part4/chapter-39">第39章</a></td><td>质量保证</td><td>质量体系、过程控制、不符合项管理、根本原因分析</td></tr><tr><td><a href="/avis-web/guide/part4/chapter-40">第40章</a></td><td>产品数据管理与数字化工程</td><td>PDM/PLM、构型管理、数字化线程</td></tr><tr><td><a href="/avis-web/guide/part4/chapter-41">第41章</a></td><td>数字孪生与智能运维</td><td>数字孪生架构、实时数据驱动、预测性维护</td></tr><tr><td><a href="/avis-web/guide/part4/chapter-42">第42章</a></td><td>全球产业格局</td><td>主要制造商分析、供应链地图、市场趋势</td></tr><tr><td><a href="/avis-web/guide/part4/chapter-43">第43章</a></td><td>新型材料</td><td>高温合金、陶瓷基复合材料、功能梯度材料</td></tr><tr><td><a href="/avis-web/guide/part4/chapter-45">第45章</a></td><td>数字化验证与虚拟鉴定</td><td>仿真驱动鉴定、模型V&amp;V、虚拟试验</td></tr><tr><td><a href="/avis-web/guide/part4/chapter-46">第46章</a></td><td>历史重大阀门故障分析与教训</td><td>典型案例剖析、故障树、经验教训库</td></tr><tr><td><a href="/avis-web/guide/part4/chapter-47">第47章</a></td><td>FMEA与FTA</td><td>失效模式与影响分析、故障树分析、风险优先数</td></tr><tr><td><a href="/avis-web/guide/part4/chapter-48">第48章</a></td><td>中国标准与型号实践</td><td>中国航天型号研制流程与标准应用</td></tr><tr><td><a href="/avis-web/guide/part4/chapter-49">第49章</a></td><td>常用仿真工具与软件生态</td><td>ANSYS/COMSOL/AMESim等工具选型与应用场景</td></tr><tr><td><a href="/avis-web/guide/part4/chapter-50">第50章</a></td><td>材料与标准数据库</td><td>材料性能数据库、标准文献检索、数据管理</td></tr><tr><td><a href="/avis-web/guide/part4/chapter-51">第51章</a></td><td>术语表与缩略语</td><td>航空航天阀门领域完整术语索引</td></tr><tr><td><a href="/avis-web/guide/part4/chapter-52">第52章</a></td><td>参考文献与引用来源</td><td>200+参考文献的完整列表与分类索引</td></tr></tbody></table><hr><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><ul><li><strong>技术管理者路径</strong>：第37章(系统工程管理) → 第38章(项目管理) → 第39章(质量保证) → 第40章(数据管理)</li><li><strong>系统工程师路径</strong>：第37章 → 第41章(数字孪生) → 第45章(虚拟鉴定) → 第46-47章(故障分析)</li><li><strong>研究人员路径</strong>：第42章(产业格局) → 第43章(新型材料) → 第49章(仿真工具) → 第50-52章(数据库与参考文献)</li></ul><hr><h2 id="相关资源" tabindex="-1">相关资源 <a class="header-anchor" href="#相关资源" aria-label="Permalink to &quot;相关资源&quot;">​</a></h2><ul><li><a href="/avis-web/guide/part3-index">第三编 制造工艺与试验验证</a> — 上一编内容</li><li><a href="/avis-web/guide/part5-index">第五编 前沿技术与未来发展</a> — 下一编内容</li></ul>',14)])])}const b=a(i,[["render",h]]);export{c as __pageData,b as default};
